// Query landscape height at a world location
void AMyActor::GetTerrainHeight(FVector Location) {
    FHitResult Hit;
    FVector Start = FVector(Location.X, Location.Y, 10000.f);
    FVector End = FVector(Location.X, Location.Y, -10000.f);

    FCollisionQueryParams Params;
    // Only hit landscape
    if (GetWorld()->LineTraceSingleByChannel(Hit, Start, End, ECC_WorldStatic, Params)) {
        if (Hit.GetActor() && Hit.GetActor()->IsA<ALandscapeProxy>()) {
            float TerrainHeight = Hit.ImpactPoint.Z;
        }
    }
}

